#include <bits/stdc++.h>
using namespace std;

const int mod=1e9+7;

long long n;
int m,k,ans[1<<5][1<<5],base[1<<5][1<<5],tmp[1<<5][1<<5],a[1<<5],sum;

int cal(int x){
    int res=0;
    for(;x;x-=x&(-x))
        res++;
    return res;
}

int main(){
    scanf("%lld%d%d",&n,&m,&k);
    long long b=n-1;
    int full=(1<<m)-1;
    for(int i=0;i<1<<m;i++){
        ans[i][i]=1;
        if(cal(i)>k)
            continue;
        base[i][i<<1&full]=1;
        if(cal(((i<<1)+1)&full)<=k)
            base[i][((i<<1)+1)&full]=1;
    }
    while(b){
        if(b&1){
            for(int i=0;i<1<<m;i++)
                for(int j=0;j<1<<m;j++)
                    tmp[i][j]=ans[i][j],ans[i][j]=0;
            for(int i=0;i<1<<m;i++)
                for(int j=0;j<1<<m;j++)
                    for(int k=0;k<1<<m;k++)
                        ans[i][j]=(ans[i][j]+1ll*tmp[i][k]*base[k][j])%mod;
        }
        for(int i=0;i<1<<m;i++)
            for(int j=0;j<1<<m;j++)
                tmp[i][j]=base[i][j],base[i][j]=0;
        for(int i=0;i<1<<m;i++)
            for(int j=0;j<1<<m;j++)
                for(int k=0;k<1<<m;k++)
                    base[i][j]=(base[i][j]+1ll*tmp[i][k]*tmp[k][j])%mod;
        b>>=1;
    }
    for(int i=0;i<1<<m;i++){
        if(cal(i)>k)
            continue;
        memset(a,0,sizeof(a));
        sum=(sum+ans[i<<1&full][i])%mod;
        if(cal(((i<<1)+1)&full)<=k)
            sum=(sum+ans[((i<<1)+1)&full][i])%mod;
    }
    printf("%d",sum);
    return 0;
}
